package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

import java.lang.reflect.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.concurrent.ConcurrentNavigableMap;
import java.util.concurrent.ConcurrentSkipListMap;

class ConstructorConstructorTest {

  @SuppressWarnings("unchecked")
  private <T> ConstructorConstructor.ObjectConstructor<T> invokeNewDefaultImplementationConstructor(Type type, Class<? super T> rawType) throws Exception {
    Method method = ConstructorConstructor.class.getDeclaredMethod("newDefaultImplementationConstructor", Type.class, Class.class);
    method.setAccessible(true);
    return (ConstructorConstructor.ObjectConstructor<T>) method.invoke(null, type, rawType);
  }

  @Test
  void testCollectionSortedSet() throws Exception {
    ConstructorConstructor.ObjectConstructor<SortedSet> constructor = invokeNewDefaultImplementationConstructor(SortedSet.class, SortedSet.class);
    assertNotNull(constructor);
    SortedSet<?> instance = constructor.construct();
    assertTrue(instance instanceof TreeSet);
  }

  @Test
  void testCollectionSet() throws Exception {
    ConstructorConstructor.ObjectConstructor<Set> constructor = invokeNewDefaultImplementationConstructor(Set.class, Set.class);
    assertNotNull(constructor);
    Set<?> instance = constructor.construct();
    assertTrue(instance instanceof LinkedHashSet);
  }

  @Test
  void testCollectionQueue() throws Exception {
    ConstructorConstructor.ObjectConstructor<Queue> constructor = invokeNewDefaultImplementationConstructor(Queue.class, Queue.class);
    assertNotNull(constructor);
    Queue<?> instance = constructor.construct();
    assertTrue(instance instanceof ArrayDeque);
  }

  @Test
  void testCollectionOther() throws Exception {
    ConstructorConstructor.ObjectConstructor<Collection> constructor = invokeNewDefaultImplementationConstructor(Collection.class, Collection.class);
    assertNotNull(constructor);
    Collection<?> instance = constructor.construct();
    assertTrue(instance instanceof ArrayList);
  }

  @Test
  void testMapConcurrentNavigableMap() throws Exception {
    ConstructorConstructor.ObjectConstructor<ConcurrentNavigableMap> constructor = invokeNewDefaultImplementationConstructor(ConcurrentNavigableMap.class, ConcurrentNavigableMap.class);
    assertNotNull(constructor);
    ConcurrentNavigableMap<?, ?> instance = constructor.construct();
    assertTrue(instance instanceof ConcurrentSkipListMap);
  }

  @Test
  void testMapConcurrentMap() throws Exception {
    ConstructorConstructor.ObjectConstructor<ConcurrentMap> constructor = invokeNewDefaultImplementationConstructor(ConcurrentMap.class, ConcurrentMap.class);
    assertNotNull(constructor);
    ConcurrentMap<?, ?> instance = constructor.construct();
    assertTrue(instance instanceof ConcurrentHashMap);
  }

  @Test
  void testMapSortedMap() throws Exception {
    ConstructorConstructor.ObjectConstructor<SortedMap> constructor = invokeNewDefaultImplementationConstructor(SortedMap.class, SortedMap.class);
    assertNotNull(constructor);
    SortedMap<?, ?> instance = constructor.construct();
    assertTrue(instance instanceof TreeMap);
  }

  @Test
  void testMapParameterizedTypeKeyNotString() throws Exception {
    // Create a ParameterizedType with key type not assignable from String
    ParameterizedType paramType = new ParameterizedType() {
      @Override public Type[] getActualTypeArguments() {
        return new Type[] {Integer.class, String.class};
      }
      @Override public Type getRawType() {
        return Map.class;
      }
      @Override public Type getOwnerType() {
        return null;
      }
    };

    ConstructorConstructor.ObjectConstructor<Map> constructor = invokeNewDefaultImplementationConstructor(paramType, Map.class);
    assertNotNull(constructor);
    Map<?, ?> instance = constructor.construct();
    assertTrue(instance instanceof LinkedHashMap);
  }

  @Test
  void testMapDefault() throws Exception {
    // type not ParameterizedType
    ConstructorConstructor.ObjectConstructor<Map> constructor = invokeNewDefaultImplementationConstructor(Map.class, Map.class);
    assertNotNull(constructor);
    Map<?, ?> instance = constructor.construct();
    assertTrue(instance instanceof com.google.gson.internal.LinkedTreeMap);
  }

  @Test
  void testNonCollectionNonMapReturnsNull() throws Exception {
    ConstructorConstructor.ObjectConstructor<String> constructor = invokeNewDefaultImplementationConstructor(String.class, String.class);
    assertNull(constructor);
  }
}
